export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-ID') || crypto.randomUUID();

    // The worker is accessible to any service binding
    // We log the caller info for traceability
    const callerInfo = {
      isInternal: request.headers.get('X-Internal-Request') === 'true',
      gatewayTimestamp: request.headers.get('X-Gateway-Timestamp'),
      requestId
    };

    console.log(`[UserService] ${method} ${path}`, JSON.stringify(callerInfo));

    try {
      // Simple router
      if (path === '/health') {
        return jsonResponse({ service: 'user-service', status: 'healthy', timestamp: new Date().toISOString() });
      }

      if (path === '/users' && method === 'GET') {
        return await listUsers(env, requestId);
      }

      if (path === '/users' && method === 'POST') {
        return await createUser(request, env, requestId);
      }

      const userMatch = path.match(/^\/users\/([^/]+)$/);
      if (userMatch) {
        const userId = userMatch[1];
        if (method === 'GET') return await getUser(userId, env, requestId);
        if (method === 'PUT') return await updateUser(userId, request, env, requestId);
        if (method === 'DELETE') return await deleteUser(userId, env, requestId);
      }

      // Internal endpoint: validate user (called by other services via service bindings)
      const validateMatch = path.match(/^\/users\/([^/]+)\/validate$/);
      if (validateMatch && method === 'GET') {
        return await validateUser(validateMatch[1], env, requestId);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (err) {
      console.error(`[UserService] Error: ${err.message}`, err.stack);
      return jsonResponse({
        error: 'Internal Service Error',
        message: err.message,
        requestId
      }, 500);
    }
  }
};

async function listUsers(env, requestId) {
  // Using KV for simple storage; in production you'd use D1 or Durable Objects
  const listResult = await env.USER_STORE.list({ prefix: 'user:' });
  const users = [];

  for (const key of listResult.keys) {
    const userData = await env.USER_STORE.get(key.name, 'json');
    if (userData) users.push(userData);
  }

  return jsonResponse({
    data: users,
    count: users.length,
    requestId
  });
}

async function getUser(userId, env, requestId) {
  const user = await env.USER_STORE.get(`user:${userId}`, 'json');

  if (!user) {
    return jsonResponse({ error: 'User not found', userId, requestId }, 404);
  }

  return jsonResponse({ data: user, requestId });
}

async function createUser(request, env, requestId) {
  const body = await request.json();

  if (!body.name || !body.email) {
    return jsonResponse({ error: 'name and email are required', requestId }, 400);
  }

  const userId = crypto.randomUUID();
  const user = {
    id: userId,
    name: body.name,
    email: body.email,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };

  await env.USER_STORE.put(`user:${userId}`, JSON.stringify(user));

  // If we need to notify other services, we can use service bindings
  // For example, notify the order service about the new user
  if (env.ORDER_SERVICE) {
    try {
      await env.ORDER_SERVICE.fetch(new Request('https://internal/hooks/user-created', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-Request-ID': requestId },
        body: JSON.stringify({ userId, email: user.email })
      }));
    } catch (err) {
      console.warn(`[UserService] Failed to notify order service: ${err.message}`);
    }
  }

  return jsonResponse({ data: user, requestId }, 201);
}

async function updateUser(userId, request, env, requestId) {
  const existing = await env.USER_STORE.get(`user:${userId}`, 'json');
  if (!existing) {
    return jsonResponse({ error: 'User not found', userId, requestId }, 404);
  }

  const body = await request.json();
  const updated = {
    ...existing,
    ...body,
    id: userId, // prevent ID override
    updatedAt: new Date().toISOString()
  };

  await env.USER_STORE.put(`user:${userId}`, JSON.stringify(updated));
  return jsonResponse({ data: updated, requestId });
}

async function deleteUser(userId, env, requestId) {
  const existing = await env.USER_STORE.get(`user:${userId}`, 'json');
  if (!existing) {
    return jsonResponse({ error: 'User not found', userId, requestId }, 404);
  }

  await env.USER_STORE.delete(`user:${userId}`);
  return jsonResponse({ message: 'User deleted', userId, requestId });
}

async function validateUser(userId, env, requestId) {
  const user = await env.USER_STORE.get(`user:${userId}`, 'json');
  return jsonResponse({
    valid: !!user,
    userId,
    requestId
  });
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' }
  });
}


