// ============================================
// worker-product-service/src/index.js
// Internal product service worker
// ============================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-ID') || crypto.randomUUID();

    console.log(`[ProductService] ${method} ${path} requestId=${requestId}`);

    try {
      if (path === '/health') {
        return jsonResponse({
          service: 'product-service',
          status: 'healthy',
          timestamp: new Date().toISOString()
        });
      }

      if (path === '/products' && method === 'GET') {
        return await listProducts(env, url, requestId);
      }

      if (path === '/products' && method === 'POST') {
        return await createProduct(request, env, requestId);
      }

      const productMatch = path.match(/^\/products\/([^/]+)$/);
      if (productMatch) {
        const productId = productMatch[1];
        if (method === 'GET') return await getProduct(productId, env, requestId);
        if (method === 'PUT') return await updateProduct(productId, request, env, requestId);
        if (method === 'DELETE') return await deleteProduct(productId, env, requestId);
      }

      // Internal endpoint: check stock (called by order service)
      const stockMatch = path.match(/^\/products\/([^/]+)\/stock$/);
      if (stockMatch && method === 'GET') {
        return await checkStock(stockMatch[1], env, requestId);
      }

      // Internal endpoint: reserve stock
      const reserveMatch = path.match(/^\/products\/([^/]+)\/reserve$/);
      if (reserveMatch && method === 'POST') {
        return await reserveStock(reserveMatch[1], request, env, requestId);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (err) {
      console.error(`[ProductService] Error: ${err.message}`, err.stack);
      return jsonResponse({
        error: 'Internal Service Error',
        message: err.message,
        requestId
      }, 500);
    }
  }
};

async function listProducts(env, url, requestId) {
  const category = url.searchParams.get('category');
  const prefix = category ? `product:${category}:` : 'product:';

  const listResult = await env.PRODUCT_STORE.list({ prefix });
  const products = [];

  for (const key of listResult.keys) {
    const product = await env.PRODUCT_STORE.get(key.name, 'json');
    if (product) products.push(product);
  }

  return jsonResponse({ data: products, count: products.length, requestId });
}

async function getProduct(productId, env, requestId) {
  // Search across all keys since we use category prefix
  const listResult = await env.PRODUCT_STORE.list({ prefix: 'product:' });

  for (const key of listResult.keys) {
    const product = await env.PRODUCT_STORE.get(key.name, 'json');
    if (product && product.id === productId) {
      return jsonResponse({ data: product, requestId });
    }
  }

  return jsonResponse({ error: 'Product not found', productId, requestId }, 404);
}

async function createProduct(request, env, requestId) {
  const body = await request.json();

  if (!body.name || !body.price || !body.category) {
    return jsonResponse({ error: 'name, price, and category are required', requestId }, 400);
  }

  const productId = crypto.randomUUID();
  const product = {
    id: productId,
    name: body.name,
    description: body.description || '',
    price: parseFloat(body.price),
    category: body.category,
    stock: body.stock || 0,
    reservedStock: 0,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };

  const key = `product:${product.category}:${productId}`;
  await env.PRODUCT_STORE.put(key, JSON.stringify(product));

  return jsonResponse({ data: product, requestId }, 201);
}

async function updateProduct(productId, request, env, requestId) {
  const listResult = await env.PRODUCT_STORE.list({ prefix: 'product:' });
  let existingKey = null;
  let existing = null;

  for (const key of listResult.keys) {
    const product = await env.PRODUCT_STORE.get(key.name, 'json');
    if (product && product.id === productId) {
      existingKey = key.name;
      existing = product;
      break;
    }
  }

  if (!existing) {
    return jsonResponse({ error: 'Product not found', productId, requestId }, 404);
  }

  const body = await request.json();
  const updated = {
    ...existing,
    ...body,
    id: productId,
    updatedAt: new Date().toISOString()
  };

  // If category changed, update the key
  const newKey = `product:${updated.category}:${productId}`;
  if (newKey !== existingKey) {
    await env.PRODUCT_STORE.delete(existingKey);
  }
  await env.PRODUCT_STORE.put(newKey, JSON.stringify(updated));

  return jsonResponse({ data: updated, requestId });
}

async function deleteProduct(productId, env, requestId) {
  const listResult = await env.PRODUCT_STORE.list({ prefix: 'product:' });

  for (const key of listResult.keys) {
    const product = await env.PRODUCT_STORE.get(key.name, 'json');
    if (product && product.id === productId) {
      await env.PRODUCT_STORE.delete(key.name);
      return jsonResponse({ message: 'Product deleted', productId, requestId });
    }
  }

  return jsonResponse({ error: 'Product not found', productId, requestId }, 404);
}

async function checkStock(productId, env, requestId) {
  const listResult = await env.PRODUCT_STORE.list({ prefix: 'product:' });

  for (const key of listResult.keys) {
    const product = await env.PRODUCT_STORE.get(key.name, 'json');
    if (product && product.id === productId) {
      return jsonResponse({
        productId,
        stock: product.stock,
        reservedStock: product.reservedStock || 0,
        availableStock: product.stock - (product.reservedStock || 0),
        requestId
      });
    }
  }

  return jsonResponse({ error: 'Product not found', productId, requestId }, 404);
}

async function reserveStock(productId, request, env, requestId) {
  const body = await request.json();
  const quantity = parseInt(body.quantity);

  if (!quantity || quantity <= 0) {
    return jsonResponse({ error: 'Valid quantity required', requestId }, 400);
  }

  const listResult = await env.PRODUCT_STORE.list({ prefix: 'product:' });

  for (const key of listResult.keys) {
    const product = await env.PRODUCT_STORE.get(key.name, 'json');
    if (product && product.id === productId) {
      const available = product.stock - (product.reservedStock || 0);

      if (quantity > available) {
        return jsonResponse({
          error: 'Insufficient stock',
          available,
          requested: quantity,
          requestId
        }, 409);
      }

      product.reservedStock = (product.reservedStock || 0) + quantity;
      product.updatedAt = new Date().toISOString();
      await env.PRODUCT_STORE.put(key.name, JSON.stringify(product));

      return jsonResponse({
        reserved: true,
        productId,
        quantity,
        remainingAvailable: product.stock - product.reservedStock,
        requestId
      });
    }
  }

  return jsonResponse({ error: 'Product not found', productId, requestId }, 404);
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' }
  });
}


