export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-ID') || crypto.randomUUID();

    console.log(`[OrderService] ${method} ${path} requestId=${requestId}`);

    try {
      if (path === '/health') {
        return jsonResponse({
          service: 'order-service',
          status: 'healthy',
          timestamp: new Date().toISOString()
        });
      }

      if (path === '/orders' && method === 'GET') {
        return await listOrders(env, url, requestId);
      }

      if (path === '/orders' && method === 'POST') {
        return await createOrder(request, env, requestId);
      }

      const orderMatch = path.match(/^\/orders\/([^/]+)$/);
      if (orderMatch) {
        const orderId = orderMatch[1];
        if (method === 'GET') return await getOrder(orderId, env, requestId);
        if (method === 'PUT') return await updateOrderStatus(orderId, request, env, requestId);
      }

      // Get orders by user
      const userOrdersMatch = path.match(/^\/orders\/user\/([^/]+)$/);
      if (userOrdersMatch && method === 'GET') {
        return await getOrdersByUser(userOrdersMatch[1], env, requestId);
      }

      // Internal webhook: user created notification
      if (path === '/hooks/user-created' && method === 'POST') {
        return await handleUserCreated(request, env, requestId);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (err) {
      console.error(`[OrderService] Error: ${err.message}`, err.stack);
      return jsonResponse({
        error: 'Internal Service Error',
        message: err.message,
        requestId
      }, 500);
    }
  }
};

async function createOrder(request, env, requestId) {
  const body = await request.json();

  if (!body.userId || !body.items || !Array.isArray(body.items) || body.items.length === 0) {
    return jsonResponse({
      error: 'userId and items array are required',
      requestId
    }, 400);
  }

  // Step 1: Validate user exists via User Service binding
  const userValidation = await env.USER_SERVICE.fetch(
    new Request(`https://internal/users/${body.userId}/validate`, {
      headers: { 'X-Request-ID': requestId }
    })
  );
  const userResult = await userValidation.json();

  if (!userResult.valid) {
    return jsonResponse({
      error: 'Invalid user',
      userId: body.userId,
      requestId
    }, 400);
  }

  // Step 2: Check and reserve stock for each item via Product Service binding
  const reservations = [];
  const failedReservations = [];

  for (const item of body.items) {
    if (!item.productId || !item.quantity) {
      failedReservations.push({
        productId: item.productId,
        error: 'productId and quantity required'
      });
      continue;
    }

    // Check stock availability
    const stockCheck = await env.PRODUCT_SERVICE.fetch(
      new Request(`https://internal/products/${item.productId}/stock`, {
        headers: { 'X-Request-ID': requestId }
      })
    );
    const stockResult = await stockCheck.json();

    if (stockCheck.status !== 200) {
      failedReservations.push({
        productId: item.productId,
        error: stockResult.error || 'Product not found'
      });
      continue;
    }

    if (stockResult.availableStock < item.quantity) {
      failedReservations.push({
        productId: item.productId,
        error: 'Insufficient stock',
        available: stockResult.availableStock,
        requested: item.quantity
      });
      continue;
    }

    // Reserve stock
    const reserveResponse = await env.PRODUCT_SERVICE.fetch(
      new Request(`https://internal/products/${item.productId}/reserve`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Request-ID': requestId
        },
        body: JSON.stringify({ quantity: item.quantity })
      })
    );
    const reserveResult = await reserveResponse.json();

    if (reserveResponse.status === 200 && reserveResult.reserved) {
      reservations.push({
        productId: item.productId,
        quantity: item.quantity,
        reserved: true
      });
    } else {
      failedReservations.push({
        productId: item.productId,
        error: reserveResult.error || 'Reservation failed'
      });
    }
  }

  if (failedReservations.length > 0) {
    // In a real system, you'd rollback successful reservations here
    return jsonResponse({
      error: 'Some items could not be reserved',
      failedItems: failedReservations,
      requestId
    }, 409);
  }

  // Step 3: Create the order
  const orderId = crypto.randomUUID();
  const order = {
    id: orderId,
    userId: body.userId,
    items: reservations,
    status: 'confirmed',
    totalItems: reservations.reduce((sum, r) => sum + r.quantity, 0),
    shippingAddress: body.shippingAddress || null,
    notes: body.notes || '',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };

  await env.ORDER_STORE.put(`order:${orderId}`, JSON.stringify(order));
  // Also index by user for quick lookups
  await env.ORDER_STORE.put(`user-order:${body.userId}:${orderId}`, orderId);

  return jsonResponse({ data: order, requestId }, 201);
}

async function listOrders(env, url, requestId) {
  const listResult = await env.ORDER_STORE.list({ prefix: 'order:' });
  const orders = [];

  for (const key of listResult.keys) {
    const order = await env.ORDER_STORE.get(key.name, 'json');
    if (order) orders.push(order);
  }

  return jsonResponse({ data: orders, count: orders.length, requestId });
}

async function getOrder(orderId, env, requestId) {
  const order = await env.ORDER_STORE.get(`order:${orderId}`, 'json');

  if (!order) {
    return jsonResponse({ error: 'Order not found', orderId, requestId }, 404);
  }

  // Enrich order with current user info from user service
  try {
    const userResp = await env.USER_SERVICE.fetch(
      new Request(`https://internal/users/${order.userId}`, {
        headers: { 'X-Request-ID': requestId }
      })
    );

    if (userResp.status === 200) {
      const userData = await userResp.json();
      order.user = userData.data;
    }
  } catch (err) {
    console.warn(`[OrderService] Could not enrich user data: ${err.message}`);
  }

  // Enrich with current product info
  for (const item of order.items) {
    try {
      const productResp = await env.PRODUCT_SERVICE.fetch(
        new Request(`https://internal/products/${item.productId}`, {
          headers: { 'X-Request-ID': requestId }
        })
      );

      if (productResp.status === 200) {
        const productData = await productResp.json();
        item.product = productData.data;
      }
    } catch (err) {
      console.warn(`[OrderService] Could not enrich product data: ${err.message}`);
    }
  }

  return jsonResponse({ data: order, requestId });
}

async function getOrdersByUser(userId, env, requestId) {
  // First validate the user
  const userValidation = await env.USER_SERVICE.fetch(
    new Request(`https://internal/users/${userId}/validate`, {
      headers: { 'X-Request-ID': requestId }
    })
  );
  const userResult = await userValidation.json();

  if (!userResult.valid) {
    return jsonResponse({ error: 'User not found', userId, requestId }, 404);
  }

  const listResult = await env.ORDER_STORE.list({ prefix: `user-order:${userId}:` });
  const orders = [];

  for (const key of listResult.keys) {
    const orderId = await env.ORDER_STORE.get(key.name, 'text');
    if (orderId) {
      const order = await env.ORDER_STORE.get(`order:${orderId}`, 'json');
      if (order) orders.push(order);
    }
  }

  return jsonResponse({ data: orders, count: orders.length, userId, requestId });
}

async function updateOrderStatus(orderId, request, env, requestId) {
  const order = await env.ORDER_STORE.get(`order:${orderId}`, 'json');

  if (!order) {
    return jsonResponse({ error: 'Order not found', orderId, requestId }, 404);
  }

  const body = await request.json();
  const validStatuses = ['confirmed', 'processing', 'shipped', 'delivered', 'cancelled'];

  if (!body.status || !validStatuses.includes(body.status)) {
    return jsonResponse({
      error: 'Invalid status',
      validStatuses,
      requestId
    }, 400);
  }

  order.status = body.status;
  order.updatedAt = new Date().toISOString();

  if (body.status === 'cancelled') {
    order.cancelledAt = new Date().toISOString();
    order.cancellationReason = body.reason || 'No reason provided';
    // In production: release reserved stock back to product service
  }

  await env.ORDER_STORE.put(`order:${orderId}`, JSON.stringify(order));

  return jsonResponse({ data: order, requestId });
}

async function handleUserCreated(request, env, requestId) {
  const body = await request.json();
  console.log(`[OrderService] New user registered: ${body.userId} (${body.email})`);

  // Could initialize user preferences, welcome offers, etc.
  return jsonResponse({
    acknowledged: true,
    userId: body.userId,
    requestId
  });
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' }
  });
}


