// ============================================
// shared/middleware.js
// Shared middleware utilities for all workers
// ============================================

export class ServiceMiddleware {
  constructor(serviceName) {
    this.serviceName = serviceName;
  }

  // Rate limiting per caller
  async rateLimit(request, env, limit = 100, windowSeconds = 60) {
    const clientId = request.headers.get('CF-Connecting-IP') ||
                     request.headers.get('X-Request-ID') ||
                     'unknown';

    const key = `ratelimit:${this.serviceName}:${clientId}`;
    const current = parseInt(await env.RATE_LIMIT_STORE?.get(key) || '0');

    if (current >= limit) {
      return {
        limited: true,
        response: new Response(JSON.stringify({
          error: 'Rate limit exceeded',
          retryAfter: windowSeconds
        }), {
          status: 429,
          headers: {
            'Content-Type': 'application/json',
            'Retry-After': String(windowSeconds)
          }
        })
      };
    }

    if (env.RATE_LIMIT_STORE) {
      await env.RATE_LIMIT_STORE.put(key, String(current + 1), {
        expirationTtl: windowSeconds
      });
    }

    return { limited: false };
  }

  // Request logging
  logRequest(request, requestId) {
    const logEntry = {
      service: this.serviceName,
      method: request.method,
      url: request.url,
      requestId,
      timestamp: new Date().toISOString(),
      isInternal: request.headers.get('X-Internal-Request') === 'true'
    };
    console.log(JSON.stringify(logEntry));
  }

  // Standardized error response
  errorResponse(message, status = 500, requestId = null) {
    return new Response(JSON.stringify({
      error: message,
      service: this.serviceName,
      requestId,
      timestamp: new Date().toISOString()
    }), {
      status,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

// Circuit breaker for service-to-service calls
export class CircuitBreaker {
  constructor(env, serviceName, options = {}) {
    this.env = env;
    this.serviceName = serviceName;
    this.failureThreshold = options.failureThreshold || 5;
    this.resetTimeoutMs = options.resetTimeoutMs || 30000;
    this.store = env.CIRCUIT_BREAKER_STORE;
  }

  async call(fetchFn) {
    const stateKey = `circuit:${this.serviceName}`;

    if (this.store) {
      const state = await this.store.get(stateKey, 'json');

      if (state && state.status === 'open') {
        const elapsed = Date.now() - state.lastFailure;
        if (elapsed < this.resetTimeoutMs) {
          throw new Error(`Circuit breaker OPEN for ${this.serviceName}. Try again in ${Math.ceil((this.resetTimeoutMs - elapsed) / 1000)}s`);
        }
        // Half-open: allow one request through
      }
    }

    try {
      const result = await fetchFn();

      if (this.store) {
        await this.store.put(stateKey, JSON.stringify({
          status: 'closed',
          failures: 0,
          lastSuccess: Date.now()
        }), { expirationTtl: 300 });
      }

      return result;
    } catch (err) {
      if (this.store) {
        const state = await this.store.get(stateKey, 'json') || { failures: 0 };
        const failures = (state.failures || 0) + 1;

        await this.store.put(stateKey, JSON.stringify({
          status: failures >= this.failureThreshold ? 'open' : 'closed',
          failures,
          lastFailure: Date.now()
        }), { expirationTtl: 300 });
      }

      throw err;
    }
  }
}


